import tensorflow as tf
from tensorflow.keras import layers, models
from flask import Flask, request, jsonify
import pandas as pd
from sklearn.model_selection import train_test_split
from tensorflow.keras.preprocessing.image import ImageDataGenerator

app = Flask(__name__)

# Define the model architecture
def create_model():
    model = models.Sequential([
        layers.Conv2D(32, (3, 3), activation='relu', input_shape=(150, 150, 3)),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(64, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(128, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Flatten(),
        layers.Dense(512, activation='relu'),
        layers.Dense(10, activation='softmax')
    ])
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])
    return model

# Load and preprocess data
def load_and_preprocess_data(csv_path):
    df = pd.read_csv(csv_path)
    train_df, val_df = train_test_split(df, test_size=0.2, random_state=42)

    train_datagen = ImageDataGenerator(rescale=1./255, rotation_range=40, width_shift_range=0.2,
                                       height_shift_range=0.2, shear_range=0.2, zoom_range=0.2,
                                       horizontal_flip=True, fill_mode='nearest')
    val_datagen = ImageDataGenerator(rescale=1./255)

    train_generator = train_datagen.flow_from_dataframe(train_df, x_col='image_path', y_col='label',
                                                     target_size=(150, 150), batch_size=32,
                                                     class_mode='sparse')
    val_generator = val_datagen.flow_from_dataframe(val_df, x_col='image_path', y_col='label',
                                                   target_size=(150, 150), batch_size=32,
                                                   class_mode='sparse')

    return train_generator, val_generator

# Train the model
@app.route('/train', methods=['POST'])
def train_model():
    file = request.files['data']
    if file:
        file_path = "uploads/" + file.filename
        file.save(file_path)
        train_generator, val_generator = load_and_preprocess_data(file_path)
        model = create_model()
        model.fit(train_generator, epochs=10, validation_data=val_generator)
        model.save('model.h5')
        return jsonify({'message': 'Model trained and saved successfully'}), 200
    else:
        return jsonify({'error': 'No file uploaded'}), 400

if __name__ == '__main__':
    app.run(debug=True)